import { __decorate } from "tslib";
import { ChangeDetectionStrategy, Component, ElementRef, EventEmitter, HostListener, Input, Output, ViewEncapsulation, inject, } from '@angular/core';
import { LucideAngularModule, Globe, ChevronDown } from 'lucide-angular';
/**
 * Sélecteur de langue compact (cf. décision J.2).
 * Liste de langues fournie par l'app, pas de hardcoding.
 */
let PfLanguageSwitcherComponent = class PfLanguageSwitcherComponent {
    constructor() {
        this.languages = [];
        this.value = '';
        this.triggerAriaLabel = 'Changer la langue';
        this.languageChange = new EventEmitter();
        this.open = false;
        this.GlobeIcon = Globe;
        this.ChevronDownIcon = ChevronDown;
        this.host = inject((ElementRef));
    }
    toggle() {
        this.open = !this.open;
    }
    select(code) {
        this.languageChange.emit(code);
        this.open = false;
    }
    onDocClick(event) {
        if (!this.open)
            return;
        if (!this.host.nativeElement.contains(event.target)) {
            this.open = false;
        }
    }
    onEscape() {
        this.open = false;
    }
    static { this.propDecorators = {
        languages: [{ type: Input }],
        value: [{ type: Input }],
        triggerAriaLabel: [{ type: Input }],
        languageChange: [{ type: Output }],
        onDocClick: [{ type: HostListener, args: ['document:click', ['$event'],] }],
        onEscape: [{ type: HostListener, args: ['document:keydown.escape',] }]
    }; }
};
PfLanguageSwitcherComponent = __decorate([
    Component({
        selector: 'pf-language-switcher',
        standalone: true,
        imports: [LucideAngularModule],
        changeDetection: ChangeDetectionStrategy.OnPush,
        encapsulation: ViewEncapsulation.None,
        template: `
    <div class="ds-language-switcher">
      <button
        type="button"
        class="ds-language-switcher__trigger"
        aria-haspopup="listbox"
        [attr.aria-expanded]="open"
        [attr.aria-label]="triggerAriaLabel"
        (click)="toggle()"
      >
        <lucide-icon [img]="GlobeIcon" [size]="14" aria-hidden="true"></lucide-icon>
        {{ value }}
        <lucide-icon [img]="ChevronDownIcon" [size]="14" aria-hidden="true"></lucide-icon>
      </button>
      @if (open) {
        <ul role="listbox" class="ds-language-switcher__menu">
          @for (lang of languages; track lang.code) {
            <li role="presentation">
              <button
                type="button"
                role="option"
                class="ds-language-switcher__option"
                [attr.aria-checked]="lang.code === value"
                (click)="select(lang.code)"
              >{{ lang.label }}</button>
            </li>
          }
        </ul>
      }
    </div>
  `,
    })
], PfLanguageSwitcherComponent);
export { PfLanguageSwitcherComponent };
